function abc(n: number): number {
  let a: number = 2;
  let b: number = 1;
  let c: boolean = true;

  while (b < n) {
    c = (a % 4 == 0) && (b % 3 < 2);
    if ((a >= 2 && b < a)) {
      b = b * -2;
    } else if (a % 2 == 0 || b % 2 == 0) {
      a = a - b;
    }
    console.log(a, b, c);
  }

  if (!c) {
    return a * -b;
  } else {
    return -a * b;
  }
}

